          // Add newline after content blocks only if they had content
          if (event.event?.type === 'content_block_stop' && hasContentInBlock) {
            process.stdout.write('\n');
            output += '\n';
            hasContentInBlock = false;
          }
        }

        // Also capture final result
        if (event.type === 'result' && event.result) {
          // Result contains full text, but we already printed it incrementally
          // Just ensure output has it for completion check
          if (!output.includes(event.result)) {
            output = event.result;
          }
        }
      } catch {
        // Ignore JSON parse errors for incomplete/malformed lines
      }
    }
  }

  // Process any remaining buffer
  if (buffer.trim()) {
    try {
      const event: StreamEvent = JSON.parse(buffer);
      if (event.type === 'result' && event.result) {
        if (!output) output = event.result;
      }
    } catch {
      // Ignore
    }
  }

  reader.releaseLock();

  const exitCode = await proc.exited;
  console.log(); // Newline after streaming output

  return {
    output,
    exitCode,
  };
}

async function main(): Promise<void> {
  let cleanupCalled = false;

  const cleanup = (signal: string) => {
    if (cleanupCalled) return;
    cleanupCalled = true;
    console.log();
    log(`Script interrupted by ${signal}. Cleaning up...`);
    const exitCode = signal === 'SIGINT' ? 130 : 143;
    process.exit(exitCode);
  };

