  console.log(
    `${COLORS.red}==========================================${COLORS.reset}`,
  );
  log(`MAX ITERATIONS REACHED (${CONFIG.maxIterations})`, COLORS.red);
  log('Loop stopped - tasks may still be pending', COLORS.red);
  console.log(
    `${COLORS.red}==========================================${COLORS.reset}`,
  );
  process.exit(1);
}

