     1→#!/usr/bin/env bun
     2→
     3→/**
     4→ * Ralph Loop - Automated Claude Code Task Executor
     5→ *
     6→ * Based on Geoffrey Huntley's Ralph Wiggum technique:
     7→ * - Fresh context per iteration (new Claude instance each time)
     8→ * - Memory persists through files only (git, progress.txt)
     9→ * - One task per iteration
    10→ * - Completion signal terminates loop
    11→ *
    12→ * Uses Claude CLI's --output-format stream-json for real-time streaming.
    13→ *
    14→ * @see https://ghuntley.com/ralph/
    15→ */
    16→
    17→import { appendFileSync } from 'node:fs';
    18→
    19→function parseMaxIterations(arg: string | undefined): number {
    20→  const parsed = parseInt(arg ?? '100', 10);
    21→  if (isNaN(parsed) || parsed <= 0) {
    22→    console.error('Error: maxIterations must be a positive integer');
    23→    process.exit(1);
    24→  }
    25→  return parsed;
    26→}
    27→
    28→const CONFIG = Object.freeze({
    29→  maxIterations: parseMaxIterations(Bun.argv[2]),
    30→  delayBetweenIterations: 5000,
    31→  logFile: './loop.log',
    32→  progressFile: './.claude/progress.txt',
    33→  iterationTimeout: 600000, // 10 minutes max per iteration
    34→  // Dual-condition exit gate: requires explicit RALPH_STATUS with exit: true
    35→  exitPattern: /RALPH_STATUS:\s*\{[^}]*"exit":\s*true[^}]*\}/,
    36→});
    37→
    38→const COLORS = Object.freeze({
    39→  red: '\x1b[0;31m',
    40→  green: '\x1b[0;32m',
    41→  yellow: '\x1b[1;33m',
    42→  blue: '\x1b[0;34m',
    43→  reset: '\x1b[0m',
    44→});
    45→
    46→// Module-scope process reference for cleanup on signals
    47→let currentProc: ReturnType<typeof Bun.spawn> | null = null;
    48→
    49→const TASK_PROMPT = `Read \`./.claude/progress.txt\`, pick the most important pending task, execute it, update the file, commit, and stop.
    50→
    51→IMPORTANT RULES:
    52→- Do NOT change logic, only migrate structure
    53→- The source of truth is card-place, consult it only if in doubt
    54→- The code has already been copied to this repository
    55→- Everything must be migrated to the new architecture/Style Guide (./.claude/STYLE_GUIDE.md)
    56→
    57→WORKFLOW:
    58→1. Read progress.txt and identify the most important pending single task
    59→2. If NO pending tasks exist, signal completion (see OUTPUT STATUS below) and stop
    60→3. If there is a task:
    61→   a. Update task status to "in progress" in progress.txt
    62→   b. Execute migration following STYLE_GUIDE.md
    63→   c. Launch 3 review agent to deeply review the work, giving
    64→      the entire context of the task, simulating pull request.
    65→   d. Review output and consider improvements
    66→   e. Implement corrections if needed
    67→   f. Update progress.txt marking task as completed
    68→   g. Commit changes
    69→   h. Output status block (see below)
    70→   i. Stop
    71→
    72→OUTPUT STATUS (REQUIRED at end of EVERY response):
    73→You MUST output this exact format at the END of your response:
    74→
    75→RALPH_STATUS: { "exit": <true if ALL tasks done, false otherwise>, "task": "<completed task name>", "remaining": <number of pending tasks> }
    76→
    77→Examples:
    78→- Task completed but more remain: RALPH_STATUS: { "exit": false, "task": "Create usePoints hook", "remaining": 5 }
    79→- ALL tasks completed: RALPH_STATUS: { "exit": true, "task": "Delete Redux files", "remaining": 0 }
    80→
    81→CRITICAL (THINK BEFORE ACTING):
    82→1. The FIRST thing you MUST do is write your understanding of each WORKFLOW statement
    83→2. The SECOND thing you MUST do is write your understanding of the work in progress described in progress.txt
    84→3. Only AFTER completing steps 1 and 2, proceed with the task execution
    85→4. If more work is necessary, add a new task to the file, set "exit": false, and Stop
    86→5. Only set "exit": true when ALL tasks in progress.txt are completed
    87→`;
    88→
    89→function log(message: string, color?: string): void {
    90→  const timestamp = new Date().toISOString().replace('T', ' ').slice(0, 19);
    91→  const line = `[${timestamp}] ${message}`;
    92→  const coloredLine = color ? `${color}${line}${COLORS.reset}` : line;
    93→
    94→  console.log(coloredLine);
    95→  appendFileSync(CONFIG.logFile, line + '\n');
    96→}
    97→
    98→async function checkDependencies(): Promise<void> {
    99→  const result = await Bun.$`which claude`.quiet().nothrow();
   100→  if (result.exitCode !== 0) {
   101→    log(
   102→      "ERROR: 'claude' command not found. Install Claude Code CLI.",
   103→      COLORS.red,
   104→    );
   105→    process.exit(1);
   106→  }
   107→
   108→  const progressFile = Bun.file(CONFIG.progressFile);
   109→  if (!(await progressFile.exists())) {
   110→    log(`ERROR: Progress file not found: ${CONFIG.progressFile}`, COLORS.red);
   111→    process.exit(1);
   112→  }
   113→}
   114→
   115→function printHeader(): void {
   116→  console.log();
   117→  console.log(
   118→    `${COLORS.blue}==========================================${COLORS.reset}`,
   119→  );
   120→  console.log(`${COLORS.blue}   Ralph Loop - Bun.js Edition${COLORS.reset}`);
   121→  console.log(
   122→    `${COLORS.blue}==========================================${COLORS.reset}`,
   123→  );
   124→  console.log(
   125→    `Max iterations: ${COLORS.yellow}${CONFIG.maxIterations}${COLORS.reset}`,
   126→  );
   127→  console.log(`Log file: ${COLORS.yellow}${CONFIG.logFile}${COLORS.reset}`);
   128→  console.log(
   129→    `Delay between iterations: ${COLORS.yellow}${CONFIG.delayBetweenIterations / 1000}s${COLORS.reset}`,
   130→  );
   131→  console.log();
   132→}
   133→
   134→interface StreamEvent {
   135→  type: string;
   136→  event?: {
   137→    type: string;
   138→    delta?: {
   139→      type: string;
   140→      text?: string;
   141→    };
   142→  };
   143→  result?: string;
   144→}
   145→
   146→async function runIteration(): Promise<{
   147→  output: string;
   148→  exitCode: number;
   149→}> {
   150→  log('Executing Claude Code...');
   151→
   152→  const proc = Bun.spawn(
   153→    [
   154→      'claude',
   155→      '-p',
   156→      TASK_PROMPT,
   157→      '--verbose',
   158→      '--debug',
   159→      '--dangerously-skip-permissions',
   160→      '--output-format',
   161→      'stream-json',
   162→      '--include-partial-messages',
   163→    ],
   164→    {
   165→      cwd: process.cwd(),
   166→      env: process.env,
   167→      stdout: 'pipe',
   168→      stderr: 'inherit', // Pass through stderr to console
   169→    },
   170→  );
   171→
   172→  // Store proc reference for cleanup on signals
   173→  currentProc = proc;
   174→
   175→  let output = '';
   176→  let timedOut = false;
   177→  const decoder = new TextDecoder();
   178→  let buffer = '';
   179→  let hasContentInBlock = false;
   180→
   181→  // Iteration timeout
   182→  const timeoutId = setTimeout(() => {
   183→    timedOut = true;
   184→    log('Iteration timeout reached. Killing process...', COLORS.yellow);
   185→    try {
   186→      proc.kill();
   187→    } catch {
   188→      // Process may have already exited
   189→    }
   190→  }, CONFIG.iterationTimeout);
   191→
   192→  const reader = proc.stdout.getReader();
   193→
   194→  try {
   195→    while (true) {
   196→      const { done, value } = await reader.read();
   197→      if (done) break;
   198→
   199→      buffer += decoder.decode(value, { stream: true });
   200→
   201→      // Process complete JSON lines
   202→      const lines = buffer.split('\n');
   203→      buffer = lines.pop() || ''; // Keep incomplete line in buffer
   204→
   205→      for (const line of lines) {
   206→        if (!line.trim()) continue;
   207→
   208→        try {
   209→          const event: StreamEvent = JSON.parse(line);
   210→
   211→          // Extract text from stream deltas
   212→          if (event.type === 'stream_event') {
   213→            if (event.event?.type === 'content_block_start') {
   214→              hasContentInBlock = false;
   215→            }
   216→            if (event.event?.type === 'content_block_delta') {
   217→              const text = event.event.delta?.text;
   218→              if (text) {
   219→                process.stdout.write(text);
   220→                output += text;
   221→                hasContentInBlock = true;
   222→              }
   223→            }
   224→            // Add newline after content blocks only if they had content
   225→            if (
   226→              event.event?.type === 'content_block_stop' &&
   227→              hasContentInBlock
   228→            ) {
   229→              process.stdout.write('\n');
   230→              output += '\n';
   231→              hasContentInBlock = false;
   232→            }
   233→          }
   234→
   235→          // Capture final result - use only if no streaming output collected
   236→          if (event.type === 'result' && event.result) {
   237→            if (!output.trim()) {
   238→              output = event.result;
   239→            }
   240→          }
   241→        } catch {
   242→          // Ignore JSON parse errors for incomplete/malformed lines
   243→        }
   244→      }
   245→    }
   246→
   247→    // Process any remaining buffer
   248→    if (buffer.trim()) {
   249→      try {
   250→        const event: StreamEvent = JSON.parse(buffer);
   251→        if (event.type === 'result' && event.result) {
   252→          if (!output.trim()) output = event.result;
   253→        }
   254→      } catch {
   255→        // Ignore
   256→      }
   257→    }
   258→  } finally {
   259→    clearTimeout(timeoutId);
   260→    reader.releaseLock();
   261→    currentProc = null;
   262→  }
   263→
   264→  if (timedOut) {
   265→    return {
   266→      output,
   267→      exitCode: 124,
   268→    }; // Standard timeout exit code
   269→  }
   270→
   271→  const exitCode = await proc.exited;
   272→  console.log(); // Newline after streaming output
   273→
   274→  return {
   275→    output,
   276→    exitCode,
   277→  };
   278→}
   279→
   280→async function main(): Promise<void> {
   281→  let cleanupCalled = false;
   282→
   283→  const cleanup = (signal: string) => {
   284→    if (cleanupCalled) return;
   285→    cleanupCalled = true;
   286→    console.log();
   287→    log(`Script interrupted by ${signal}. Cleaning up...`);
   288→
   289→    // Kill any running Claude process
   290→    if (currentProc) {
   291→      try {
   292→        currentProc.kill();
   293→      } catch {
   294→        // Process may have already exited
   295→      }
   296→    }
   297→
   298→    const exitCode = signal === 'SIGINT' ? 130 : 143;
   299→    process.exit(exitCode);
   300→  };
   301→
   302→  process.on('SIGINT', () => cleanup('SIGINT'));
   303→  process.on('SIGTERM', () => cleanup('SIGTERM'));
   304→
   305→  await checkDependencies();
   306→  printHeader();
   307→
   308→  log('Starting automated task loop...');
   309→
   310→  for (let iteration = 1; iteration <= CONFIG.maxIterations; iteration++) {
   311→    console.log();
   312→    console.log(
   313→      `${COLORS.green}==========================================${COLORS.reset}`,
   314→    );
   315→    log(`Iteration #${iteration} / ${CONFIG.maxIterations}`, COLORS.green);
   316→    console.log(
   317→      `${COLORS.green}==========================================${COLORS.reset}`,
   318→    );
   319→    console.log();
   320→
   321→    const { output, exitCode } = await runIteration();
   322→
   323→    if (exitCode === 0) {
   324→      log('Claude Code execution completed successfully', COLORS.green);
   325→    } else {
   326→      log(
   327→        `Claude Code exited with status ${exitCode}, checking output...`,
   328→        COLORS.yellow,
   329→      );
   330→    }
   331→
   332→    // Dual-condition exit gate: requires explicit RALPH_STATUS with exit: true
   333→    const hasExitSignal = CONFIG.exitPattern.test(output);
   334→    if (hasExitSignal) {
   335→      // Extract status for logging
   336→      const match = output.match(/RALPH_STATUS:\s*(\{[^}]*\})/);
   337→      const status = match ? match[1] : 'unknown';
   338→      console.log();
   339→      console.log(
   340→        `${COLORS.green}==========================================${COLORS.reset}`,
   341→      );
   342→      log('ALL TASKS COMPLETED!', COLORS.green);
   343→      log(`Exit status: ${status}`, COLORS.green);
   344→      log(`Total iterations: ${iteration}`, COLORS.green);
   345→      console.log(
   346→        `${COLORS.green}==========================================${COLORS.reset}`,
   347→      );
   348→      process.exit(0);
   349→    }
   350→
   351→    // More specific error detection - avoid false positives from "error handling", etc.
   352→    const hasErrors =
   353→      exitCode !== 0 ||
   354→      /(?:^|\n)\s*(?:Error:|ERROR:|Failed:|FAILED:)/m.test(output) ||
   355→      output.includes('claude: error');
   356→    if (hasErrors) {
   357→      log('Warning: Potential errors detected in output.', COLORS.yellow);
   358→    }
   359→
   360→    if (iteration < CONFIG.maxIterations) {
   361→      console.log();
   362→      log(
   363→        `Waiting ${CONFIG.delayBetweenIterations / 1000} seconds before next iteration...`,
   364→      );
   365→      await Bun.sleep(CONFIG.delayBetweenIterations);
   366→    }
   367→  }
   368→
   369→  console.log();
   370→  console.log(
   371→    `${COLORS.red}==========================================${COLORS.reset}`,
   372→  );
   373→  log(`MAX ITERATIONS REACHED (${CONFIG.maxIterations})`, COLORS.red);
   374→  log('Loop stopped - tasks may still be pending', COLORS.red);
   375→  console.log(
   376→    `${COLORS.red}==========================================${COLORS.reset}`,
   377→  );
   378→  process.exit(1);
   379→}
   380→
   381→main();
